 55→/// Forward a shell command to a connected node for execution.
 56→///
 57→/// Uses `node.invoke` internally with `system.run` as the command.
 58→/// Returns the stdout/stderr/exit_code from the remote execution.
 59→pub async fn exec_on_node(
 60→    state: &Arc<GatewayState>,
 61→    node_id: &str,
 62→    command: &str,
 63→    timeout_secs: u64,
 64→    cwd: Option<&str>,
 65→    env: Option<&HashMap<String, String>>,
 66→) -> anyhow::Result<NodeExecResult> {
 67→    // Build the args for system.run.
 68→    let mut args = serde_json::json!({
 69→        "command": command,
 70→        "timeout": timeout_secs * 1000, // ms
 71→    });
 72→
 73→    if let Some(cwd) = cwd {
 74→        args["cwd"] = serde_json::json!(cwd);
 75→    }
 76→
 77→    // Filter env to safe allowlist.
 78→    if let Some(env_map) = env {
 79→        let filtered = filter_env(env_map);
 80→        if !filtered.is_empty() {
 81→            args["env"] = serde_json::to_value(filtered)?;
 82→        }
 83→    }
 84→
 85→    // Look up node connection.
 86→    let conn_id = {
 87→        let inner = state.inner.read().await;
 88→        let node = inner
 89→            .nodes
 90→            .get(node_id)
 91→            .ok_or_else(|| anyhow::anyhow!("node '{node_id}' not connected"))?;
 92→        node.conn_id.clone()
 93→    };
 94→
 95→    // Build and send the invoke request.
 96→    let invoke_id = uuid::Uuid::new_v4().to_string();
 97→    let invoke_event = moltis_protocol::EventFrame::new(
 98→        "node.invoke.request",
 99→        serde_json::json!({
100→            "invokeId": invoke_id,
101→            "command": "system.run",
102→            "args": args,
103→        }),
104→        state.next_seq(),
105→    );
106→    let event_json = serde_json::to_string(&invoke_event)?;
107→
108→    {
109→        let inner = state.inner.read().await;
110→        let node_client = inner
111→            .clients
112→            .get(&conn_id)
113→            .ok_or_else(|| anyhow::anyhow!("node connection lost"))?;
114→        if !node_client.send(&event_json) {
115→            anyhow::bail!("failed to send invoke to node");
116→        }
117→    }
118→
119→    // Register the pending invoke and wait for result.
120→    let (tx, rx) = tokio::sync::oneshot::channel();
121→    {
122→        let mut inner = state.inner.write().await;
123→        inner
124→            .pending_invokes
125→            .insert(invoke_id.clone(), crate::state::PendingInvoke {
126→                request_id: invoke_id.clone(),
127→                sender: tx,
128→                created_at: std::time::Instant::now(),
129→            });
130→    }
131→
132→    let timeout = Duration::from_secs(timeout_secs.max(5));
133→    let result = match tokio::time::timeout(timeout, rx).await {
134→        Ok(Ok(value)) => value,
135→        Ok(Err(_)) => {
136→            anyhow::bail!("node invoke cancelled");
137→        },
138→        Err(_) => {
139→            state.inner.write().await.pending_invokes.remove(&invoke_id);
140→            anyhow::bail!("node invoke timeout after {timeout_secs}s");
141→        },
142→    };
143→
144→    // Parse the result.
145→    parse_exec_result(&result)
146→}
