234→/// Resolve a node identifier (id or display name) to a node_id.
235→pub async fn resolve_node_id(state: &Arc<GatewayState>, node_ref: &str) -> Option<String> {
236→    let inner = state.inner.read().await;
237→
238→    // Try direct id match first.
239→    if inner.nodes.get(node_ref).is_some() {
240→        return Some(node_ref.to_string());
241→    }
242→
243→    // Try display name match (case-insensitive).
244→    let lower = node_ref.to_lowercase();
245→    for node in inner.nodes.list() {
246→        if let Some(name) = &node.display_name
247→            && name.to_lowercase() == lower
248→        {
249→            return Some(node.node_id.clone());
250→        }
251→    }
252→
253→    None
254→}
