256→/// Filter environment variables to the safe allowlist.
257→fn filter_env(env: &HashMap<String, String>) -> HashMap<String, String> {
258→    env.iter()
259→        .filter(|(key, _)| is_safe_env(key))
260→        .map(|(k, v)| (k.clone(), v.clone()))
261→        .collect()
262→}
263→
264→fn is_safe_env(key: &str) -> bool {
265→    // Block dangerous prefixes first.
266→    for prefix in BLOCKED_ENV_PREFIXES {
267→        if key.starts_with(prefix) {
268→            return false;
269→        }
270→    }
271→
272→    // Allow exact matches.
273→    if SAFE_ENV_ALLOWLIST.contains(&key) {
274→        return true;
275→    }
276→
277→    // Allow prefix matches.
278→    for prefix in SAFE_ENV_PREFIX_ALLOWLIST {
279→        if key.starts_with(prefix) {
280→            return true;
281→        }
282→    }
283→
284→    false
285→}
