287→fn parse_exec_result(value: &serde_json::Value) -> anyhow::Result<NodeExecResult> {
288→    // Try structured result first.
289→    if let Some(stdout) = value.get("stdout").and_then(|v| v.as_str()) {
290→        return Ok(NodeExecResult {
291→            stdout: stdout.to_string(),
292→            stderr: value
293→                .get("stderr")
294→                .and_then(|v| v.as_str())
295→                .unwrap_or_default()
296→                .to_string(),
297→            exit_code: value.get("exitCode").and_then(|v| v.as_i64()).unwrap_or(0) as i32,
298→        });
299→    }
300→
301→    // Check for error.
302→    if let Some(error) = value.get("error").and_then(|v| v.as_str()) {
303→        anyhow::bail!("node exec error: {error}");
304→    }
305→
306→    // Return the raw value as stdout.
307→    Ok(NodeExecResult {
308→        stdout: value.to_string(),
309→        stderr: String::new(),
310→        exit_code: 0,
311→    })
312→}
