        let result = tool
            .execute(serde_json::json!({
                "command": "echo empty",
                "node": ""
            }))
            .await
            .unwrap();
        assert_eq!(result["stdout"].as_str().unwrap().trim(), "empty");
        assert_eq!(result["exit_code"], 0);
    }

